<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Theme Toggle with Singleton Pattern</title>

    <style>
        /* CSS Variables for Themes */
        :root {
            --bg-color: #ffffff; /* Light theme default */
            --text-color: #000000;
            --accent-color: #007bff;
        }

        body.dark-theme {
            --bg-color: #333333; /* Dark theme */
            --text-color: #ffffff;
        }

        body {
            background-color: var(--bg-color);
            color: var(--text-color);
            font-family: Arial, sans-serif;
