<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Theme Toggle with Singleton Pattern</title>

    <!-- CSS Styles -->
    <style>
        /* Define CSS variables for themes */
        :root {
            --background-color: #ffffff; /* Light theme default */
            --text-color: #000000;
            --accent-color: #007bff;
        }

        body.dark-theme {
            --background-color: #333333; /* Dark theme override */
            --text-color: #ffffff;
            --accent-color: #61dafb;
        }

        body {
            background-color: var(--background-color);
