            const toggleButton = document.getElementById('theme-toggle');

            toggleButton.addEventListener('click', function() {
                themeManager.toggleTheme(); // Toggle the theme
                this.textContent = themeManager.getTheme() === 'light' ? 'Switch to Dark Theme' : 'Switch to Light Theme'; // Update button text
            });

            // Initialize with default theme (though it's already set)
